                             f"{quantize_weights=}, "
                             f"{quantize_activations=}, "
                             f"{per_token=}, "
                             f"{per_channel=}, "
                             f"{per_group=}, "
                             f"{use_int4_weights=}, "
                             f"{use_int8_kv_cache=}, "
                             f"{use_fp8_kv_cache=}, "
                             f"{use_fp8_qdq=}, "
                             f"{use_fp8_block_scales=}, "
                             f"{use_fp8_rowwise=}, "
